async (params, browser) => {
  // Open product page
  await browser.open(`${params.product_url}`)

  // Wait for product page to load
  await browser.waitForSelector('body', 15000)

  // Let page render
  await browser.wait(2000)

  // Scroll down to reviews section
  await browser.scroll({ direction: 'down', amount: 3000 })

  await browser.wait(2000)

  // Scroll further to load more reviews
  await browser.scroll({ direction: 'down', amount: 2000 })

  await browser.wait(2000)

  // Extract reviews
  const reviews_data = await browser.evaluate(`const reviews = []; const reviewSelectors = [ '.spr-review', '.jdgm-rev', '.loox-review', '.stamped-review', '.yotpo-review', '[class*="review-card"]', '[class*="ReviewCard"]', '.review-item', '.review' ]; let reviewEls = []; for (const sel of reviewSelectors) { const found = document.querySelectorAll(sel); if (found.length > 0) { reviewEls = found; break; } } for (let i = 0; i < Math.min(reviewEls.length, 20); i++) { const el = reviewEls[i]; const authorEl = el.querySelector('.spr-review-header-byline, .jdgm-rev__author, .loox-review-author, .stamped-review-author, .yotpo-user-name, [class*="author"], [class*="reviewer"], .review-author'); const ratingEl = el.querySelector('.spr-icon-star, .jdgm-star, .loox-rating, .stamped-review-rating, .yotpo-review-stars, [class*="star-rating"], [class*="StarRating"]'); const titleEl = el.querySelector('.spr-review-header-title, .jdgm-rev__title, .loox-review-title, .stamped-review-header-title, .yotpo-review-title, [class*="review-title"], .review-title'); const bodyEl = el.querySelector('.spr-review-content-body, .jdgm-rev__body, .loox-review-content, .stamped-review-content-body, .yotpo-review-content, [class*="review-body"], [class*="review-content"], .review-body, .review-content'); const dateEl = el.querySelector('.spr-review-header-byline, .jdgm-rev__timestamp, .loox-review-date, .stamped-review-date, .yotpo-review-date, [class*="review-date"], time'); let starCount = 0; const starEls = el.querySelectorAll('.spr-icon-star, .jdgm-star.jdgm--on, .stamped-fa-star, [class*="star-filled"], [class*="star"][class*="active"]'); if (starEls.length > 0) starCount = starEls.length; const ratingAttr = el.querySelector('[data-rating], [data-score]'); if (ratingAttr) starCount = parseInt(ratingAttr.dataset.rating || ratingAttr.dataset.score || '0'); reviews.push({ author: authorEl ? authorEl.textContent.trim().replace(/^by\s*/i, '') : 'Anonymous', rating: starCount > 0 ? starCount + '/5' : (ratingEl ? ratingEl.textContent.trim() : ''), title: titleEl ? titleEl.textContent.trim() : '', content: bodyEl ? bodyEl.textContent.trim().substring(0, 800) : '', date: dateEl ? dateEl.textContent.trim() : '' }); } const overallEl = document.querySelector('.spr-summary-starrating, .jdgm-prev-badge, .stamped-badge, .yotpo-bottomline .yotpo-stars, [class*="average-rating"], [class*="overall-rating"]'); const overallCountEl = document.querySelector('.spr-summary-actions-togglereviews, .jdgm-prev-badge__text, .stamped-badge-caption, .yotpo-sum-reviews, [class*="review-count"], [class*="total-reviews"]'); return { overall_rating: overallEl ? overallEl.textContent.trim() : '', total_reviews: overallCountEl ? overallCountEl.textContent.trim() : '', scraped_count: reviews.length, reviews: reviews, url: window.location.href }`)

  return reviews_data
}
